17	<script src="https://accounts.google.com/gsi/client" async defer></script>
18	<script>if ('scrollRestoration' in history) history.scrollRestoration = 'manual';</script>
19	<style>
20	/* ===== PAGE-SPECIFIC TOKENS ===== */
21	:root {
22	  /* 12 user colors: vivid (name) + pastel (bubble) */
23	  --user-1: #B91C1C; --user-1-bg: #FEE2E2;
24	  --user-2: #C2410C; --user-2-bg: #FFEDD5;
25	  --user-3: #B45309; --user-3-bg: #FEF9C3;
26	  --user-4: #4D7C0F; --user-4-bg: #ECFCCB;
27	  --user-5: #047857; --user-5-bg: #D1FAE5;
28	  --user-6: #0F766E; --user-6-bg: #CCFBF1;
29	  --user-7: #0369A1; --user-7-bg: #E0F2FE;
30	  --user-8: #1D4ED8; --user-8-bg: #DBEAFE;
31	  --user-9: #4338CA; --user-9-bg: #E0E7FF;
32	  --user-10: #7E22CE; --user-10-bg: #F3E8FF;
33	  --user-11: #A21CAF; --user-11-bg: #FAE8FF;
34	  --user-12: #BE185D; --user-12-bg: #FCE7F3;
35	  --user-self: #64748B; --user-self-bg: #E2E8F0;
36	}
37	/* ===== BASE OVERRIDES ===== */
38	html, body { padding: 0; height: 100%; font-size: var(--font-base); overscroll-behavior: none; touch-action: pan-x pan-y; -webkit-tap-highlight-color: transparent; }
39	
40	/* ===== COMPONENTS ===== */
41	
42	/* --- Layout --- */
43	.app { display: flex; flex-direction: column; height: 100vh; }
44	.header { display: flex; align-items: center; height: var(--header-h); background: var(--gray-900); color: #fff; padding: 0 var(--space-lg); flex-shrink: 0; z-index: var(--z-header); position: relative; }
45	.header .back { background: none; border: none; color: #fff; font-size: var(--font-xl); cursor: pointer; padding: var(--space-sm); margin-right: var(--space-sm); line-height: 1; }
46	.header .title { flex: 1; font-weight: 600; font-size: var(--font-base); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
47	.header .online { font-size: var(--font-xs); color: var(--gray-400); }
48	.header .header-info { flex: 1; min-width: 0; display: flex; flex-direction: column; justify-content: center; gap: 1px; padding-left: 40px; padding-right: 40px; }
49	.header .header-info .title { font-size: var(--font-sm); line-height: 1.2; }
50	.header .header-info .online { display: block; line-height: 1.2; }
51	.header .header-avatar { width: 30px; height: 30px; border-radius: 50%; overflow: hidden; cursor: pointer; flex-shrink: 0; border: 1.5px solid rgba(255,255,255,0.5); }
52	.header .header-avatar img { width: 100%; height: 100%; object-fit: cover; }
53	.icon-user { vertical-align: -3.5px; }
54	.icon-lock { vertical-align: -2px; margin-right: 4px; opacity: 0.85; flex-shrink: 0; }
55	.header-count { display: none; }
56	.content { flex: 1; overflow-y: auto; -webkit-overflow-scrolling: touch; overflow-anchor: none; scrollbar-width: none; }
57	.content::-webkit-scrollbar { display: none; }
58	
59	/* --- Tabs --- */
60	.tabs { display: flex; box-shadow: 0 1px 0 var(--color-border); background: var(--color-bg); height: var(--header-h); flex-shrink: 0; }
61	.tabs button { flex: 1; background: none; border: none; font-size: var(--font-sm); color: var(--color-muted); cursor: pointer; border-bottom: 2px solid transparent; font-family: inherit; }
62	.tabs button.active { color: var(--color-text); font-weight: 600; border-bottom-color: var(--color-text); }
63	
64	/* --- Room list --- */
65	.room-list { list-style: none; margin: 0; padding: 0; }
66	.room-item { display: flex; align-items: center; gap: var(--space-md); padding: 0 var(--space-lg); height: var(--header-h); border-bottom: 1px solid var(--color-surface); cursor: pointer; box-sizing: border-box; -webkit-tap-highlight-color: transparent; }
67	.room-item:active:not(:has(:active)) { background: var(--color-surface); }
68	.room-info { flex: 1; min-width: 0; }
69	.room-name { font-weight: 600; font-size: var(--font-sm); line-height: 1.5; }
70	.room-badge { flex-shrink: 0; display: flex; align-items: center; }
71	.room-meta { display: none; }
72	.room-count { font-size: var(--font-xs); color: var(--gray-400); line-height: 1.2; }
73	.room-desc { display: none; }
74	.room-member-icon { display: none; }
75	.room-bell { padding: 0; border: none; background: none; cursor: pointer; display: flex; align-items: center; justify-content: center; color: var(--gray-400); flex-shrink: 0; -webkit-tap-highlight-color: transparent; }
76	.room-bell.active { color: var(--color-text); }
77	@media (hover: hover) { .room-bell:hover { background: var(--color-surface); } }
78	
79	/* --- Avatar --- */
80	.avatar { width: 36px; height: 36px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-weight: 700; font-size: var(--font-sm); color: #fff; flex-shrink: 0; }
81	.avatar-sm { width: 28px; height: 28px; font-size: var(--font-xs); border-radius: 50%; display: flex; align-items: center; justify-content: center; font-weight: 700; color: #fff; flex-shrink: 0; }
82	
83	/* --- Messages --- */
84	.messages { padding: var(--space-lg) var(--space-md) var(--space-sm); display: flex; flex-direction: column; gap: 2px; min-height: 100%; justify-content: flex-end; -webkit-user-select: none; user-select: none; -webkit-touch-callout: none; }
85	.msg { display: flex; gap: var(--space-sm); padding: var(--space-md) 0; align-items: flex-end; }
86	.msg.msg-mine { justify-content: flex-end; }
87	.msg-bubble { position: relative; padding: var(--space-md) var(--space-md) var(--space-2xl); max-width: min(70%, 480px); min-width: 80px; display: inline-block; word-break: break-word; -webkit-user-select: none; user-select: none; -webkit-touch-callout: none; }
88	.msg-mine-bubble { background: var(--user-self-bg); color: var(--color-text); border-radius: var(--radius-lg) var(--radius-lg) var(--radius-sm) var(--radius-lg); }
89	.msg-other-bubble { background: var(--color-surface); color: var(--color-text); border-radius: var(--radius-lg) var(--radius-lg) var(--radius-lg) var(--radius-sm); }
90	.msg-header { display: flex; gap: var(--space-sm); align-items: baseline; margin-bottom: 2px; }
91	.msg-name { font-weight: 600; font-size: var(--font-xs); cursor: pointer; }
92	.msg-time { position: absolute; bottom: var(--space-md); right: var(--space-md); font-size: var(--font-xs); color: var(--color-muted); }
93	.msg-text { font-size: var(--font-base); line-height: 1.5; }
94	.msg-text.msg-decrypt-failed { font-style: italic; color: var(--color-muted); background: rgba(0,0,0,0.05); border-radius: var(--radius-sm); padding: 2px 6px; display: inline-block; }
95	.dm-e2ee-banner { text-align: center; text-wrap: balance; padding: var(--space-sm) var(--space-xl) var(--space-md); color: var(--color-muted); font-size: var(--font-xs); line-height: 1.4; }
96	.msg-image { max-width: 260px; max-height: 260px; border-radius: var(--radius-md); margin-top: var(--space-xs); display: block; -webkit-touch-callout: none; cursor: pointer; }
97	.msg-video-wrap { position: relative; display: inline-block; margin-top: var(--space-xs); cursor: pointer; }
98	.msg-video { max-width: 260px; max-height: 260px; border-radius: var(--radius-md); display: block; -webkit-touch-callout: none; }
99	.msg-video-play { position: absolute; top: 50%; left: 50%; transform: translate(-50%,-50%); width: 48px; height: 48px; color: #fff; filter: drop-shadow(0 1px 4px rgba(0,0,0,0.5)); pointer-events: none; transition: opacity 0.15s; }
100	.msg-video-wrap.playing .msg-video-play { opacity: 0; }
101	.msg-video-fullscreen { position: absolute; bottom: var(--space-md); right: var(--space-md); width: 22px; height: 22px; color: #fff; filter: drop-shadow(0 1px 3px rgba(0,0,0,0.7)); opacity: 0; transition: opacity 0.15s; cursor: pointer; }
102	.msg-video-wrap.playing .msg-video-fullscreen { opacity: 0.8; }
103	.msg-pending { opacity: 0.5; }
104	
105	/* --- Message cards (meetup + location) --- */
106	.msg-card { background: var(--color-surface); border-radius: var(--radius-md); padding: var(--space-md); margin-top: var(--space-xs); width: 260px; display: block; text-decoration: none; color: inherit; cursor: pointer; }
107	.msg-card:active { background: var(--color-surface-hover); }
108	.msg-card .card-label { font-size: var(--font-xs); color: var(--color-accent); font-weight: 700; margin-bottom: var(--space-xs); }
109	.msg-card .card-title { font-weight: 600; font-size: var(--font-sm); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
110	.msg-card .card-meta { font-size: var(--font-xs); color: var(--color-muted); margin-top: var(--space-xs); }
111	.msg-card.card-meetup { background: var(--user-1-bg); box-shadow: inset 0 0 0 1px var(--color-accent); }
112	.meetup-join { display: inline-block; padding: var(--space-xs) var(--space-md); border: 1px solid var(--color-accent); border-radius: var(--radius-pill); font-size: var(--font-xs); font-weight: 600; cursor: pointer; background: none; color: var(--color-accent); font-family: inherit; margin-top: var(--space-sm); }
113	.meetup-join.joined { background: var(--color-accent); color: #fff; }
114	.meetup-going { font-weight: 400; }
115	.meetup-join-wide { width: 260px; display: block; margin-top: var(--space-xs); padding: var(--space-sm) var(--space-md); border-radius: var(--radius-md); font-size: var(--font-sm); }
116	.msg-card.card-location { background: var(--user-5-bg); box-shadow: inset 0 0 0 1px var(--color-success); }
117	.msg-card.card-location .card-label { color: var(--color-success); }
118	
119	/* --- Link preview --- */
120	.msg-link-preview { display: block; text-decoration: none; color: inherit; margin-bottom: var(--space-sm); border-radius: var(--radius-md); overflow: hidden; background: var(--color-surface); max-width: 480px; cursor: pointer; }
121	.msg-link-preview:active { opacity: 0.85; }
122	.link-preview-img { width: 100%; aspect-ratio: auto; display: block; -webkit-touch-callout: none; }
123	.link-preview-body { padding: 10px var(--space-md); }
124	.link-preview-title { font-weight: 600; font-size: var(--font-sm); line-height: 1.3; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
125	.link-preview-desc { font-size: var(--font-xs); color: var(--color-muted); margin-top: var(--space-xs); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; line-height: 1.4; }
126	.link-preview-domain { font-size: var(--font-xs); color: var(--color-muted); margin-top: 3px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
127	
128	/* --- Input bar --- */
129	.input-bar { display: flex; align-items: flex-end; gap: var(--space-xs); padding: var(--space-sm) var(--space-md); border-top: 1px solid var(--color-border); background: var(--color-bg); flex-shrink: 0; position: relative; }
130	.pwa-standalone .input-bar { padding-bottom: 20px; }
131	.input-bar button { background: none; border: none; padding: 0; cursor: pointer; color: var(--color-text-secondary); width: 32px; height: 32px; display: flex; align-items: center; justify-content: center; flex-shrink: 0; margin-bottom: 4px; }
132	.input-bar button svg { width: 24px; height: 24px; }
133	.input-wrap { flex: 1; position: relative; display: flex; align-items: flex-end; }
134	.input-wrap textarea { width: 100%; padding: 10px 44px 10px var(--space-lg); border: 1px solid var(--color-border); border-radius: 20px; font-size: var(--font-base); outline: none; font-family: inherit; resize: none; overflow-y: hidden; line-height: 1.4; box-sizing: content-box; scrollbar-width: none; }
135	.input-wrap textarea:focus { border-color: var(--gray-400); }
136	.input-wrap textarea.overlimit { border-color: #e53935; }
137	.input-wrap textarea.overlimit:focus { border-color: #e53935; }
138	.input-bar .send.disabled { opacity: 0.3; pointer-events: none; }
139	.input-wrap textarea::-webkit-scrollbar { display: none; }
140	.input-wrap textarea.multiline { border-radius: var(--radius-lg); }
141	.input-bar .emoji-btn { position: absolute; right: 10px; bottom: 9px; width: 22px; height: 22px; padding: 0; background: none; border: none; color: var(--color-disabled); display: flex; align-items: center; justify-content: center; margin-bottom: 0; }
142	.input-bar .emoji-btn svg { width: 22px; height: 22px; }
143	.input-bar .send { color: var(--color-text-secondary); }
144	.input-bar .send svg { width: 28px; height: 28px; }
145	
146	/* --- Action menu popup --- */
147	.action-menu { display: none; position: absolute; bottom: 100%; left: var(--space-sm); margin-bottom: var(--space-xs); background: var(--color-bg); border: 1px solid var(--color-border); border-radius: var(--radius-md); box-shadow: var(--shadow-lg); z-index: 50; overflow: hidden; }
148	.action-menu.open { display: flex; flex-direction: column; }
149	.action-menu button { display: flex; align-items: center; gap: var(--space-md); padding: var(--space-md) var(--space-xl); border: none; background: none; font-size: var(--font-sm); cursor: pointer; white-space: nowrap; text-align: left; font-family: inherit; width: 100%; height: auto; color: var(--color-text); justify-content: flex-start; }
150	.action-menu button:active { background: var(--color-surface); }
151	@media (hover: hover) { .action-menu button:hover { background: var(--color-surface); } }
152	
153	/* --- Reply preview --- */
154	.reply-preview { display: none; align-items: center; gap: var(--space-sm); padding: var(--space-sm) var(--space-md); border-top: 1px solid var(--color-border); background: var(--color-surface); flex-shrink: 0; }
155	.reply-preview.visible { display: flex; }
156	.reply-preview-content { flex: 1; min-width: 0; border-left: 3px solid var(--color-accent); padding-left: var(--space-sm); }
157	.reply-preview-name { font-weight: 600; font-size: var(--font-xs); display: block; margin-bottom: 2px; }
158	.reply-preview-text { font-size: var(--font-sm); line-height: 1.4; color: var(--color-muted); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; display: block; }
159	.reply-preview-close { background: none; border: none; font-size: 18px; color: var(--color-muted); cursor: pointer; padding: var(--space-xs) var(--space-sm); }
160	
161	/* --- Reply quote in message --- */
162	.reply-quote { border-left: 3px solid var(--color-accent); padding: var(--space-xs) var(--space-sm); margin: 6px 0; cursor: pointer; background: rgba(0,0,0,0.04); border-radius: var(--radius-sm); }
163	.msg-mine-bubble .reply-quote { background: rgba(0,0,0,0.06); }
164	.reply-quote-name { font-weight: 600; font-size: var(--font-xs); display: block; margin-bottom: 2px; }
165	.reply-quote-text { font-size: var(--font-sm); line-height: 1.4; color: var(--color-muted); display: block; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; max-width: 200px; }
166	.msg.highlight { animation: msg-highlight 1.5s ease-out; }
167	@keyframes msg-highlight { 0% { background: rgba(185,28,28,0.1); } 100% { background: transparent; } }
168	
169	/* --- Reactions --- */
170	.reaction-pills { position: absolute; bottom: -16px; display: flex; gap: 3px; z-index: 5; }
171	.msg-mine-bubble .reaction-pills { right: var(--space-sm); }
172	.msg-other-bubble .reaction-pills { left: var(--space-sm); }
173	.reaction-pill { display: inline-flex; align-items: center; justify-content: center; gap: 2px; padding: var(--space-xs) var(--space-sm); border: 1px solid var(--color-border); border-radius: var(--radius-pill); background: var(--color-surface); font-size: var(--font-sm); cursor: pointer; box-shadow: var(--shadow-sm); line-height: 1; text-align: center; }
174	.reaction-pill.own { border-color: var(--color-accent); }
175	.react-btn { opacity: 0; position: absolute; top: 50%; transform: translateY(-50%); background: var(--color-bg); border: 1px solid var(--color-border); border-radius: 50%; width: 30px; height: 30px; display: flex; align-items: center; justify-content: center; cursor: pointer; z-index: var(--z-sticky); box-shadow: var(--shadow-sm); transition: opacity var(--transition-fast); color: var(--color-text-secondary); }
176	.react-btn svg { width: 20px; height: 20px; flex-shrink: 0; }
177	@media (hover: hover) { .msg-bubble:hover .react-btn { opacity: 1; } }
178	.react-btn.active { opacity: 1; }
179	.msg-other-bubble .react-btn { left: auto; right: -38px; }
180	.msg-mine-bubble .react-btn { right: auto; left: -38px; }
181	.msg-bubble::after { content: ''; position: absolute; top: 0; bottom: 0; width: 88px; }
182	.msg-other-bubble::after { right: -88px; }
183	.msg-mine-bubble::after { left: -88px; }
184	.reaction-picker { display: flex; gap: 2px; background: var(--color-bg); border: 1px solid var(--color-border); border-radius: var(--radius-pill); padding: var(--space-xs) 6px; box-shadow: var(--shadow-md); position: fixed; z-index: var(--z-toast); white-space: nowrap; }
185	.reaction-picker button { background: none; border: none; font-size: var(--font-xl); padding: var(--space-xs) 6px; cursor: pointer; border-radius: 50%; }
186	@media (hover: hover) { .reaction-picker button:hover { background: var(--color-surface); } }
187	
188	/* --- Action sheet (mobile bottom drawer / desktop centered modal) --- */
189	.action-sheet-overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.4); z-index: var(--z-popup); display: flex; align-items: center; justify-content: center; opacity: 0; transition: opacity 0.2s; -webkit-user-select: none; user-select: none; -webkit-touch-callout: none; }
190	.action-sheet-overlay.open { opacity: 1; }
191	.action-sheet { background: var(--color-bg); width: 90%; max-width: 360px; border-radius: var(--radius-lg); padding: var(--space-sm) 0 0; transform: scale(0.95); opacity: 0; transition: transform 0.2s, opacity 0.2s; -webkit-user-select: none; user-select: none; overflow: hidden; }
192	.action-sheet > :last-child { padding-bottom: calc(var(--space-md) + var(--space-sm)); }
193	.action-sheet-overlay.open .action-sheet { transform: scale(1); opacity: 1; }
194	.action-sheet-title { text-align: center; font-weight: 600; font-size: var(--font-base); color: var(--color-muted); padding: var(--space-md) var(--space-lg); border-bottom: 1px solid var(--color-border); }
195	.action-sheet-desc { text-align: center; font-size: var(--font-sm); color: var(--color-muted); padding: var(--space-md) var(--space-lg); margin: 0; border-bottom: 1px solid var(--color-border); }
196	.action-sheet-btn { display: block; width: 100%; padding: var(--space-md) var(--space-lg); border: none; background: none; font-size: var(--font-base); cursor: pointer; text-align: center; font-family: inherit; color: var(--color-text); }
197	@media (hover: hover) { .action-sheet-btn:active { background: var(--color-surface); } }
198	.action-sheet-danger { color: var(--color-accent); }
199	.action-sheet-cancel { color: var(--color-muted); border-top: 1px solid var(--color-border); margin-top: var(--space-xs); }
200	
201	/* --- Image/video viewer --- */
202	.image-viewer { position: fixed; inset: 0; background: rgba(0,0,0,0.9); z-index: var(--z-toast); display: flex; align-items: center; justify-content: center; opacity: 0; transition: opacity 0.2s; }
203	.image-viewer.open { opacity: 1; }
204	.image-viewer img { max-width: 90%; max-height: 90%; object-fit: contain; border-radius: var(--radius-sm); }
205	.viewer-close { position: absolute; top: var(--space-md); right: var(--space-md); width: 32px; height: 32px; filter: drop-shadow(0 1px 3px rgba(0,0,0,0.5)); opacity: 0.8; cursor: pointer; }
206	
207	/* --- Video trim editor --- */
208	.trim-editor video { width: 100%; border-radius: 0; display: block; background: #000; }
209	.trim-controls { padding: var(--space-md) var(--space-lg); display: flex; flex-direction: column; gap: var(--space-sm); }
210	.trim-track { position: relative; height: 32px; background: var(--color-surface); border-radius: var(--radius-sm); cursor: pointer; }
211	.trim-range { position: absolute; top: 0; height: 100%; background: rgba(0,0,0,0.12); border-radius: var(--radius-sm); }
212	.trim-handle { position: absolute; top: 0; width: 12px; height: 100%; background: var(--color-text); border-radius: 3px; cursor: ew-resize; z-index: 2; }
213	.trim-handle::after { content: ''; position: absolute; top: 50%; left: 50%; transform: translate(-50%,-50%); width: 2px; height: 12px; background: #fff; border-radius: 1px; }
214	.trim-playhead { position: absolute; top: 0; width: 2px; height: 100%; background: var(--color-accent); z-index: 1; pointer-events: none; }
215	.trim-times { display: flex; justify-content: space-between; font-size: var(--font-xs); color: var(--color-muted); }
216	.trim-duration { text-align: center; font-size: var(--font-sm); font-weight: 600; }
217	
218	/* --- Modal --- */
219	.modal-overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.5); z-index: var(--z-popup); display: flex; align-items: center; justify-content: center; opacity: 0; transition: opacity 0.2s; }
220	.modal-overlay.open { opacity: 1; }
221	.modal { background: var(--color-bg); width: calc(100% - var(--space-2xl)); max-width: 400px; border-radius: var(--radius-lg); overflow: visible; transform: scale(0.95); transition: transform 0.2s; }
222	.modal-overlay.open .modal { transform: scale(1); }
223	.modal-header { display: flex; align-items: center; justify-content: space-between; padding: var(--space-md) var(--space-lg); border-bottom: 1px solid var(--color-border); }
224	.modal-title { font-weight: 600; font-size: var(--font-base); }
225	.modal-close { background: none; border: none; font-size: 22px; cursor: pointer; padding: var(--space-xs) var(--space-sm); color: var(--color-muted); }
226	.modal-body { padding: var(--space-lg); display: flex; flex-direction: column; gap: var(--space-sm); }
227	.modal-label { font-size: var(--font-xs); font-weight: 600; color: var(--color-muted); margin-top: var(--space-xs); }
228	.modal-input { padding: var(--space-md); border: 1px solid var(--color-border); border-radius: var(--radius-md); font-size: var(--font-sm); outline: none; width: 100%; font-family: inherit; }
