875	async function initAvatarEditor(file) {
876	  dbg('[AVATAR] initAvatarEditor', file.name, file.size);
877	  const bmp = await createImageBitmap(file);
878	  const origW = bmp.width, origH = bmp.height;
879	  bmp.close();
880	
881	  let previewFile = file;
882	  let natW = origW, natH = origH;
883	  const maxPreview = 2000;
884	  if (origW > maxPreview || origH > maxPreview) {
885	    const scale = maxPreview / Math.max(origW, origH);
886	    natW = Math.round(origW * scale);
887	    natH = Math.round(origH * scale);
888	    const resized = await createImageBitmap(file, { resizeWidth: natW, resizeHeight: natH, resizeQuality: 'high' });
889	    const blob = await _bitmapToBlob(resized, natW, natH);
890	    previewFile = new File([blob], 'preview.webp', { type: 'image/webp' });
891	  }
892	
893	  const previewScale = origW / natW;
894	  const minScale = 128 / Math.min(natW, natH);
895	  const maxScale = Math.max(minScale * 6, 1);
896	  const initScale = minScale * 2;
897	  _avatarState = { file, previewFile, natW, natH, origW, origH, previewScale, scale: initScale, minScale, maxScale, x: 0, y: 0 };
898	  _avatarState.x = -(natW * initScale - 128) / 2;
899	  _avatarState.y = -(natH * initScale - 128) / 2;
900	
901	  const url = URL.createObjectURL(previewFile);
902	  const el = document.getElementById('avatar-upload');
903	  el.innerHTML = `
904	    <div class="avatar-edit" id="avatar-edit">
905	      <img src="${url}" id="avatar-edit-img">
906	    </div>`;
907	  let _avatarDragged = false;
908	  el.onclick = () => { if (!_avatarDragged) uploadAvatar(); };
909	
910	  const thumb = document.getElementById('avatar-zoom-thumb');
911	  const track = document.getElementById('avatar-zoom-track');
912	  thumb.classList.remove('hidden');
913	  const initT = (initScale - minScale) / (maxScale - minScale);
914	  thumb.style.left = (initT * 86) + 'px';
915	
916	  let zLastX, zCurrentLeft;
917	  const zMove = (e) => {
918	    e.preventDefault();
919	    const cx = e.touches ? e.touches[0].clientX : e.clientX;
920	    zCurrentLeft += (cx - zLastX) * 0.4;
921	    zLastX = cx;
922	    const newLeft = Math.max(0, Math.min(86, zCurrentLeft));
923	    thumb.style.left = newLeft + 'px';
924	    const t = newLeft / 86;
925	    const s = _avatarState;
926	    const oldScale = s.scale;
927	    s.scale = s.minScale + t * (s.maxScale - s.minScale);
928	    const ratio = s.scale / oldScale;
929	    s.x = clampAvatarX(64 - (64 - s.x) * ratio);
930	    s.y = clampAvatarY(64 - (64 - s.y) * ratio);
