1602	async function loadRooms() {
1603	  dbg('[ROOM] loadRooms');
1604	  try { rooms = await api('/rooms'); } catch { rooms = []; }
1605	  verify('loadRooms', rooms.length > 0, rooms.length + ' rooms loaded');
1606	  // GET /rooms only ever returns stage/general rooms -- merge instead of
