        ${u.avatar_url ? '<img src="' + esc(u.avatar_url) + '">' : '<svg viewBox="0 0 24 24" fill="none" style="width:24px;height:24px;color:var(--color-disabled)"><circle cx="12" cy="6" r="4" stroke="currentColor" stroke-width="1.5"/><path d="M20 17.5C20 19.9853 20 22 12 22C4 22 4 19.9853 4 17.5C4 15.0147 7.58172 13 12 13C16.4183 13 20 15.0147 20 17.5Z" stroke="currentColor" stroke-width="1.5"/></svg>'}
      </div>
      <div class="avatar-zoom" id="edit-avatar-zoom"><span>-</span><div class="avatar-zoom-track" id="edit-avatar-zoom-track"><div class="avatar-zoom-thumb hidden" id="edit-avatar-zoom-thumb"></div></div><span>+</span></div>
